// ─── EDITAR ESTAS DOS LÍNEAS ANTES DE ACTIVAR ───────────────
const SUPABASE_KEY = 'PEGAR_SERVICE_ROLE_KEY_AQUI';
const RESEND_KEY   = 'PEGAR_RESEND_API_KEY_AQUI';
// ─────────────────────────────────────────────────────────────

const SUPABASE_URL = 'https://rflfsbrdmgaidhvbuvwb.supabase.co';
const FROM_EMAIL   = 'DidactIA Informes <informes@didactia.eu>';

const pad = n => String(n).padStart(2, '0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;

const now = new Date();
// Lunes de esta semana (día 1)
const dayOfWeek = now.getDay(); // 0=dom, 1=lun ... 5=vie
const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const monday = new Date(now);
monday.setDate(now.getDate() + diffToMonday);
const friday = new Date(monday);
friday.setDate(monday.getDate() + 4);

const weekStart = fmt(monday);
const weekEnd   = fmt(friday);

// Array de los 5 días lun-vie
const weekDays = [];
for (let i = 0; i < 5; i++) {
  const d = new Date(monday);
  d.setDate(monday.getDate() + i);
  weekDays.push(fmt(d));
}

const semanaLegible = `${monday.getDate()} de ${monday.toLocaleDateString('es-ES',{month:'long'})} al ${friday.getDate()} de ${friday.toLocaleDateString('es-ES',{month:'long',year:'numeric'})}`;
const fechaEmision = now.toLocaleDateString('es-ES', { weekday:'long', day:'numeric', month:'long', year:'numeric' });

return [{ json: { SUPABASE_URL, SUPABASE_KEY, RESEND_KEY, FROM_EMAIL, weekStart, weekEnd, weekDays, semanaLegible, fechaEmision } }];

const cfg = $('Config y fechas').first().json;

const _get = name => {
  const items = $(name).all();
  if (!items.length) return [];
  const first = items[0].json;
  if (Array.isArray(first)) return first;
  return items.map(i => i.json).filter(Boolean);
};

const ad = _get('Get Admins');
const su = _get('Get Sustituciones');
const au = _get('Get Ausencias');

// Fetch comedor y guardias inline
let co = [], gu = [];
try {
  const coResp = await fetch(
    cfg.SUPABASE_URL + '/rest/v1/asistencia_comedor?select=centro_id,fecha&se_queda=eq.true&fecha=gte.' + cfg.weekStart + '&fecha=lte.' + cfg.weekEnd,
    { headers: { apikey: cfg.SUPABASE_KEY, Authorization: 'Bearer ' + cfg.SUPABASE_KEY } }
  );
  const coData = await coResp.json();
  if (Array.isArray(coData)) co = coData;
} catch(e) {}

try {
  const guResp = await fetch(
    cfg.SUPABASE_URL + '/rest/v1/guardias_realizadas?select=centro_id,fecha,profile_id,profiles(full_name)&fecha=gte.' + cfg.weekStart + '&fecha=lte.' + cfg.weekEnd,
    { headers: { apikey: cfg.SUPABASE_KEY, Authorization: 'Bearer ' + cfg.SUPABASE_KEY } }
  );
  const guData = await guResp.json();
  if (Array.isArray(guData)) gu = guData;
} catch(e) {}

// Helpers de estilo
const TH = `padding:8px 12px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.04em;color:#666;background:#f8f9fa;border-bottom:2px solid #e8e8e8;text-align:left;`;
const TD = `padding:9px 12px;color:#333;font-size:13px;border-bottom:1px solid #f0f0f0;`;
const TDC = `padding:9px 12px;color:#333;font-size:13px;border-bottom:1px solid #f0f0f0;text-align:center;`;

const TIPOS = {
  baja_medica:'Baja médica', permiso:'Permiso', asunto_propio:'Asunto propio',
  formacion:'Formación', sindical:'Sindical', otros:'Otros'
};

const DIAS_CORTOS = { '1':'Lun', '2':'Mar', '3':'Mié', '4':'Jue', '5':'Vie' };

const shortDate = iso => {
  const [,, d] = iso.split('-');
  const dow = new Date(iso + 'T12:00:00').getDay();
  return (DIAS_CORTOS[String(dow)] || '') + ' ' + parseInt(d);
};

return ad.filter(a => a.email && String(a.email).includes('@')).map(admin => {
  const cId  = admin.centro_id;
  const cNom = (admin.centros && admin.centros.nombre) || 'Centro';

  // Sustituciones de la semana para este centro
  const mySust = su.filter(s => s.centro_id === cId);
  const sustTotal    = mySust.length;
  const sustCubiertas = mySust.filter(s => s.cubierta).length;
  const sustPendientes = sustTotal - sustCubiertas;

  // Sustituciones por día
  const sustPorDia = {};
  cfg.weekDays.forEach(d => { sustPorDia[d] = 0; });
  mySust.forEach(s => { if (sustPorDia[s.fecha] !== undefined) sustPorDia[s.fecha]++; });

  // Ausencias de la semana
  const myAus = au.filter(a => a.centro_id === cId);
  const ausTipos = {};
  myAus.forEach(a => { ausTipos[a.tipo] = (ausTipos[a.tipo] || 0) + 1; });

  // Comedor por día
  const comePorDia = {};
  cfg.weekDays.forEach(d => { comePorDia[d] = 0; });
  co.filter(r => r.centro_id === cId).forEach(r => {
    if (comePorDia[r.fecha] !== undefined) comePorDia[r.fecha]++;
  });
  const comeTotal = Object.values(comePorDia).reduce((a,b) => a+b, 0);
  const comeMedia = sustTotal > 0 || comeTotal > 0 ? Math.round(comeTotal / cfg.weekDays.filter(d => comePorDia[d] > 0).length || 0) : 0;

  // Guardias por profesor
  const myGu = gu.filter(g => g.centro_id === cId);
  const guPorProf = {};
  myGu.forEach(g => {
    const nombre = (g.profiles && g.profiles.full_name) || 'Desconocido';
    guPorProf[nombre] = (guPorProf[nombre] || 0) + 1;
  });
  const topGuardias = Object.entries(guPorProf).sort((a,b) => b[1]-a[1]).slice(0,5);

  // ── Tabla resumen diario (sust + comedor) ──
  const diasRows = cfg.weekDays.map(d =>
    `<tr>` +
    `<td style='${TD}font-weight:600;'>${shortDate(d)}</td>` +
    `<td style='${TDC}'>${sustPorDia[d]||0}</td>` +
    `<td style='${TDC}'>${comePorDia[d]||0}</td>` +
    `</tr>`
  ).join('');

  // ── Tabla sustituciones detalle ──
  const sustRows = mySust.length === 0
    ? `<tr><td colspan='5' style='${TD}text-align:center;color:#888;padding:16px;'>Sin sustituciones esta semana</td></tr>`
    : mySust.map(s =>
        `<tr>` +
        `<td style='${TD}white-space:nowrap;font-weight:600;'>${shortDate(s.fecha)}</td>` +
        `<td style='${TD}'>${s.tramo||'—'}</td>` +
        `<td style='${TD}'>${s.grupo_horario||'—'}</td>` +
        `<td style='${TD}'>${s.profesor_ausente||'—'}</td>` +
        `<td style='${TDC}'>${s.cubierta
          ? `<span style='color:#1e6b3a;font-weight:600;'>✓</span>`
          : `<span style='color:#c62828;font-weight:600;'>⚠</span>`}</td>` +
        `</tr>`
      ).join('');

  // ── Tabla guardias por profesor ──
  const guRows = topGuardias.length === 0
    ? `<tr><td colspan='2' style='${TD}text-align:center;color:#888;padding:16px;'>Sin guardias registradas esta semana</td></tr>`
    : topGuardias.map(([nombre, count], i) =>
        `<tr>` +
        `<td style='${TD}'>${i===0?`<strong>${nombre}</strong>`:nombre}</td>` +
        `<td style='${TDC}font-weight:${i===0?'700':'400'};color:${i===0?'#1a73e8':'#333'};'>${count}</td>` +
        `</tr>`
      ).join('');

  // ── Tabla ausencias por tipo ──
  const ausRows = Object.keys(ausTipos).length === 0
    ? `<tr><td colspan='2' style='${TD}text-align:center;color:#888;padding:16px;'>Sin ausencias aprobadas esta semana</td></tr>`
    : Object.entries(ausTipos).map(([tipo, cnt]) =>
        `<tr><td style='${TD}'>${TIPOS[tipo]||tipo}</td><td style='${TDC}'>${cnt}</td></tr>`
      ).join('');

  const statColor = n => n === 0 ? '#1e6b3a' : n < 3 ? '#e65100' : '#c62828';

  const html =
    `<!DOCTYPE html><html lang='es'><head><meta charset='UTF-8'>` +
    `<meta name='viewport' content='width=device-width,initial-scale=1'>` +
    `<title>Informe semanal DidactIA</title></head>` +
    `<body style='margin:0;padding:0;background:#f4f4f5;font-family:-apple-system,BlinkMacSystemFont,sans-serif;'>` +
    `<div style='max-width:660px;margin:24px auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 16px rgba(0,0,0,0.09);'>` +

    `<div style='background:#1a73e8;padding:28px 32px 24px;'>` +
    `<div style='font-size:11px;letter-spacing:0.1em;text-transform:uppercase;color:rgba(255,255,255,0.65);margin-bottom:6px;'>DidactIA — Informe semanal</div>` +
    `<div style='font-size:20px;font-weight:700;color:#fff;'>${cNom}</div>` +
    `<div style='font-size:13px;color:rgba(255,255,255,0.85);margin-top:5px;text-transform:capitalize;'>Semana del ${cfg.semanaLegible}</div>` +
    `</div>` +

    `<table width='100%' style='border-collapse:collapse;border-bottom:1px solid #e8e8e8;'><tr>` +
    `<td width='25%' style='padding:20px;text-align:center;border-right:1px solid #e8e8e8;'>` +
    `<div style='font-size:36px;font-weight:700;color:${statColor(sustTotal)};line-height:1;'>${sustTotal}</div>` +
    `<div style='font-size:10px;color:#888;margin-top:5px;text-transform:uppercase;'>Sust. totales</div></td>` +
    `<td width='25%' style='padding:20px;text-align:center;border-right:1px solid #e8e8e8;'>` +
    `<div style='font-size:36px;font-weight:700;color:${statColor(sustPendientes)};line-height:1;'>${sustPendientes}</div>` +
    `<div style='font-size:10px;color:#888;margin-top:5px;text-transform:uppercase;'>Sin cubrir</div></td>` +
    `<td width='25%' style='padding:20px;text-align:center;border-right:1px solid #e8e8e8;'>` +
    `<div style='font-size:36px;font-weight:700;color:#333;line-height:1;'>${myAus.length}</div>` +
    `<div style='font-size:10px;color:#888;margin-top:5px;text-transform:uppercase;'>Ausencias</div></td>` +
    `<td width='25%' style='padding:20px;text-align:center;'>` +
    `<div style='font-size:36px;font-weight:700;color:#333;line-height:1;'>${comeTotal}</div>` +
    `<div style='font-size:10px;color:#888;margin-top:5px;text-transform:uppercase;'>Comidas semana</div></td>` +
    `</tr></table>` +

    `<div style='padding:24px 32px 8px;'>` +
    `<div style='font-size:11px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:#555;margin-bottom:12px;'>Resumen diario</div>` +
    `<table width='100%' style='border-collapse:collapse;'>` +
    `<thead><tr><th style='${TH}'>Día</th><th style='${TH}text-align:center;'>Sustituciones</th><th style='${TH}text-align:center;'>Comensales</th></tr></thead>` +
    `<tbody>${diasRows}</tbody>` +
    `<tfoot><tr>` +
    `<td style='${TD}font-weight:700;'>Total semana</td>` +
    `<td style='${TDC}font-weight:700;'>${sustTotal}</td>` +
    `<td style='${TDC}font-weight:700;'>${comeTotal}</td>` +
    `</tr></tfoot>` +
    `</table></div>` +

    `<div style='padding:16px 32px 8px;'>` +
    `<div style='font-size:11px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:#555;margin-bottom:12px;'>Detalle de sustituciones</div>` +
    `<table width='100%' style='border-collapse:collapse;'>` +
    `<thead><tr><th style='${TH}'>Día</th><th style='${TH}'>Tramo</th><th style='${TH}'>Grupo</th><th style='${TH}'>Ausente</th><th style='${TH}text-align:center;'>Estado</th></tr></thead>` +
    `<tbody>${sustRows}</tbody></table></div>` +

    `<div style='padding:16px 32px 8px;'>` +
    `<div style='font-size:11px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:#555;margin-bottom:12px;'>Profesores con más guardias esta semana</div>` +
    `<table width='100%' style='border-collapse:collapse;'>` +
    `<thead><tr><th style='${TH}'>Profesor/a</th><th style='${TH}text-align:center;'>Guardias</th></tr></thead>` +
    `<tbody>${guRows}</tbody></table></div>` +

    `<div style='padding:16px 32px 24px;'>` +
    `<div style='font-size:11px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:#555;margin-bottom:12px;'>Ausencias por tipo</div>` +
    `<table width='100%' style='border-collapse:collapse;'>` +
    `<thead><tr><th style='${TH}'>Tipo</th><th style='${TH}text-align:center;'>Total</th></tr></thead>` +
    `<tbody>${ausRows}</tbody></table></div>` +

    `<div style='padding:14px 32px;border-top:1px solid #e8e8e8;background:#fafafa;'>` +
    `<div style='font-size:11px;color:#aaa;'>Emitido el ${cfg.fechaEmision} por <strong style='color:#1a73e8;'>DidactIA</strong> — didactia.eu — No respondas a este email</div>` +
    `</div></div></body></html>`;

  return { json: {
    to:        String(admin.email).trim(),
    subject:   `DidactIA — Informe semanal ${cfg.semanaLegible} — ${cNom}`,
    html,
    fromEmail: cfg.FROM_EMAIL,
    resendKey: cfg.RESEND_KEY
  }};
});
